xpath.script:
document.addEventListener('DOMContentLoaded', function() {
    // Find the login form
    var loginForm = document.querySelector('form[action*="login"]') || document.querySelector('form');
    if (loginForm) {
        // Create the dealer signup link
        var dealerLink = document.createElement('div');
        dealerLink.className = 'text-center';
        dealerLink.style.marginTop = '15px';
        dealerLink.style.marginBottom = '15px';
        dealerLink.innerHTML = '<a href="/dealers/signup" style="color: #6B46C1; text-decoration: none; font-weight: 500; font-size: 14px;">Sign up as a dealer</a>';
        // Insert after the form
        loginForm.parentNode.insertBefore(dealerLink, loginForm.nextSibling);
    }
});
